from ariadne import QueryType, ObjectType, make_executable_schema, graphql_sync
from ariadne.asgi import GraphQL
from starlette.applications import Starlette
from starlette.middleware import Middleware
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.responses import JSONResponse

# --- Data Store ---
users_db = {
    "user1": {
        "id": "user1",
        "username": "alice",
        "bio": "Software Engineer",
        "email": "alice@example.com",
        "phone": "111-222-3333",
        "address": "123 Main St",
    },
    "user2": {
        "id": "user2",
        "username": "bob",
        "bio": "Product Manager",
        "email": "bob@example.com",
        "phone": "444-555-6666",
        "address": "456 Oak Ave",
    },
}

posts_db = [
    {"id": "post1", "title": "My First Post", "content": "Hello world!", "authorId": "user1"},
    {"id": "post2", "title": "GraphQL is Fun", "content": "Learning Ariadne", "authorId": "user1"},
    {"id": "post3", "title": "New Project Ideas", "content": "Brainstorming...", "authorId": "user2"},
]

# --- Middleware for Authentication (simulated) ---
class AuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        # Simulate authentication: if 'Authorization: Bearer user1' is in headers, set current_user
        auth_header = request.headers.get("authorization")
        if auth_header and auth_header.startswith("Bearer "):
            user_id = auth_header.split(" ")[1]
            request.state.current_user = users_db.get(user_id)
        else:
            request.state.current_user = None # No user authenticated

        response = await call_next(request)
        return response

# --- Type Definitions ---
type_defs = """
    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String
        author: User!
    }

    type Query {
        me: User
        user(id: ID!): User
        users: [User!]!
        posts: [Post!]!
    }
"""

# --- Resolvers ---

query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")

@query.field("me")
def resolve_me(obj, info):
    request = info.context["request"]
    return request.state.current_user

@query.field("user")
def resolve_user(obj, info, id):
    return users_db.get(id)

@query.field("users")
def resolve_users(obj, info):
    return list(users_db.values())

@query.field("posts")
def resolve_posts(obj, info):
    return posts_db

@user_type.field("posts")
def resolve_user_posts(user, info):
    # This resolver will be called for the 'posts' field of a User object
    return [post for post in posts_db if post["authorId"] == user["id"]]

@post_type.field("author")
def resolve_post_author(post, info):
    # This resolver will be called for the 'author' field of a Post object
    return users_db.get(post["authorId"])

# --- Schema and Application Setup ---
schema = make_executable_schema(type_defs, [query, user_type, post_type])

app = Starlette(
    middleware=[
        Middleware(AuthMiddleware)
    ],
    routes=[
        GraphQL("/graphql", schema, debug=True)
    ]
)

